1	// cli.ts
2	import {
3	  quote,
4	  claim,
5	  insuranceSum,
6	  isKnownItemType,
7	  type Item,
8	} from "./claim-office.js";
9	
10	type QuoteStep = { op: "quote"; items: Item[] };
11	type ClaimStep = {
12	  op: "claim";
13	  policy: number;
14	  incident: { cause: string; damages: { itemType: string; amount: number }[] };
15	};
16	type Step = QuoteStep | ClaimStep;
17	
18	type Scenario = {
19	  customer: { yearsWithMHPCO: number };
20	  steps: Step[];
21	};
22	
23	type Policy = {
24	  items: Item[];
25	  remainingCap: number;
26	};
27	
28	type StepResult = { premium: number } | { payout: number; remainingCap: number };
29	
30	const CAP_MULTIPLIER = 2;
31	
32	async function readStdin(): Promise<string> {
33	  const chunks: Buffer[] = [];
34	  for await (const chunk of process.stdin) {
35	    chunks.push(chunk as Buffer);
36	  }
37	  return Buffer.concat(chunks).toString("utf8");
38	}
39	
40	function fail(message: string): never {
41	  console.error(message);
42	  process.exit(1);
43	}
44	
45	function validateItems(items: Item[]): void {
46	  for (const item of items) {
47	    if (!isKnownItemType(item.type)) {
48	      fail(`Unknown item type: ${item.type}`);
49	    }
50	  }
51	}
52	
53	function processQuote(
54	  step: QuoteStep,
55	  customerYears: number,
56	  previousContracts: number,
57	  policies: Policy[],
58	): StepResult {
59	  validateItems(step.items);
60	  const premium = quote({
61	    items: step.items,
62	    customerYears,
63	    previousContracts,
64	  });
65	  policies.push({
66	    items: step.items,
67	    remainingCap: insuranceSum(step.items) * CAP_MULTIPLIER,
68	  });
69	  return { premium };
70	}
71	
72	function processClaim(step: ClaimStep, policies: Policy[]): StepResult {
73	  const policy = policies[step.policy];
74	  const result = claim({
75	    items: policy.items,
76	    remainingCap: policy.remainingCap,
77	    damages: step.incident.damages,
78	  });
79	  policy.remainingCap = result.remainingCap;
80	  return result;
81	}
82	
83	async function main() {
84	  const raw = await readStdin();
85	  const scenario: Scenario = JSON.parse(raw);
86	
87	  const results: StepResult[] = [];
88	  const policies: Policy[] = [];
89	  let previousContracts = 0;
90	
91	  for (const step of scenario.steps) {
92	    if (step.op === "quote") {
93	      results.push(
94	        processQuote(step, scenario.customer.yearsWithMHPCO, previousContracts, policies),
95	      );
96	      previousContracts += 1;
97	    } else {
98	      results.push(processClaim(step, policies));
99	    }
100	  }
101	
102	  console.log(JSON.stringify({ results }));
103	}
104	
105	main().catch((err) => {
106	  console.error(err instanceof Error ? err.message : String(err));
107	  process.exit(1);
108	});
